# One exam config per course — creates if not already present
EXAM_CONFIGS = {
    "EDA 105": {"title": "EDA 105 Assessment",  "exam_type": "exam", "duration_mins": 60,  "total_marks": 20},
    "EDA 106": {"title": "EDA 106 Assessment",  "exam_type": "exam", "duration_mins": 60,  "total_marks": 20},
    "EDA 222": {"title": "EDA 222 Assessment",  "exam_type": "exam", "duration_mins": 90,  "total_marks": 25},
    "EDA 226": {"title": "EDA 226 Assessment",  "exam_type": "exam", "duration_mins": 90,  "total_marks": 22},
    "EDA 316": {"title": "EDA 316 Assessment",  "exam_type": "exam", "duration_mins": 90,  "total_marks": 21},
    "EDA 325": {"title": "EDA 325 Assessment",  "exam_type": "exam", "duration_mins": 60,  "total_marks": 19},
    "EDA 424": {"title": "EDA 424 Assessment",  "exam_type": "exam", "duration_mins": 90,  "total_marks": 18},
    "EDA 425": {"title": "EDA 425 Assessment",  "exam_type": "exam", "duration_mins": 90,  "total_marks": 18},
    "EDA 447": {"title": "EDA 447 Assessment",  "exam_type": "exam", "duration_mins": 60,  "total_marks": 19},
    "EDA 490": {"title": "EDA 490 Assessment",  "exam_type": "exam", "duration_mins": 90,  "total_marks": 20},
}


class Command(BaseCommand):
    help = "Create one exam per course and load all 202 questions + options"

    def handle(self, *args, **kwargs):
        exam_map = {}

        # ── Step 1: ensure one exam exists per course ──────────────
        self.stdout.write("Creating exams...")
        for code, cfg in EXAM_CONFIGS.items():
            try:
                course = Course.objects.get(code=code)
            except Course.DoesNotExist:
                self.stdout.write(self.style.WARNING(f"  Course {code} not found — skipping"))
                continue

            exam, created = Exam.objects.get_or_create(
                course=course,
                title=cfg["title"],
                defaults={
                    "exam_type":     cfg["exam_type"],
                    "duration_mins": cfg["duration_mins"],
                    "total_marks":   cfg["total_marks"],
                },
            )
            exam_map[code] = exam
            status = "created" if created else "exists"
            self.stdout.write(f"  Exam for {code}: {status}")

        # ── Step 2: load questions + options ───────────────────────
        self.stdout.write("\nLoading questions and options...")
        created_q = 0
        skipped_q = 0
        created_o = 0

        with transaction.atomic():
            for item in QUESTIONS:
                code = item["course"]
                if code not in exam_map:
                    self.stdout.write(self.style.WARNING(f"  No exam for {code} — skipping question"))
                    skipped_q += 1
                    continue

                exam = exam_map[code]

                q, q_created = Question.objects.get_or_create(
                    exam=exam,
                    question_text=item["question_text"],
                    defaults={
                        "question_type": item["question_type"],
                        "mark":          1,
                    },
                )

                if q_created:
                    created_q += 1
                    for opt in item["options"]:
                        Option.objects.create(
                            question=q,
                            option_value=opt["option_text"],
                            is_answer=opt["is_answer"],
                        )
                        created_o += 1

        self.stdout.write(self.style.SUCCESS(
            f"\nDone! Questions created: {created_q} | Skipped: {skipped_q} | Options created: {created_o}"
        ))
